import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => ''),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { agentWatchdog } from '../../subagent-stop/watchdog.js';
import { existsSync, readFileSync } from 'node:fs';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Agent',
    session_id: 'test-session',
    tool_input: {},
    agent_id: 'completed-agent-001',
    subagent_type: 'test-generator',
    ...overrides,
  };
}

let testCtx: ReturnType<typeof createTestContext>;

describe('agentWatchdog', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
  });

  it('returns silent success when no spawn log exists', () => {
    vi.mocked(existsSync).mockReturnValue(false);

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success when all agents are below threshold', () => {
    const twoMinAgo = new Date(Date.now() - 2 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: twoMinAgo, agent_id: 'other-agent', subagent_type: 'backend-system-architect' })
    );

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('emits warning for agent running over 5 minutes', () => {
    const sixMinAgo = new Date(Date.now() - 6 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: sixMinAgo, agent_id: 'slow-agent', subagent_type: 'workflow-architect' })
    );

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.systemMessage).toContain('WARNING');
    expect(result.systemMessage).toContain('workflow-architect');
  });

  it('emits critical alert for agent running over 10 minutes', () => {
    const elevenMinAgo = new Date(Date.now() - 11 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: elevenMinAgo, agent_id: 'hung-agent', subagent_type: 'security-auditor' })
    );

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.systemMessage).toContain('CRITICAL');
    expect(result.systemMessage).toContain('security-auditor');
    expect(result.systemMessage).toContain('Ctrl+F');
  });

  it('skips the agent that just completed', () => {
    const sixMinAgo = new Date(Date.now() - 6 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: sixMinAgo, agent_id: 'completed-agent-001', subagent_type: 'test-generator' })
    );

    const result = agentWatchdog(makeInput({ agent_id: 'completed-agent-001' }), testCtx);

    // Should NOT warn about the agent that just completed
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('handles multiple agents with mixed states', () => {
    const twoMinAgo = new Date(Date.now() - 2 * 60 * 1000).toISOString();
    const sevenMinAgo = new Date(Date.now() - 7 * 60 * 1000).toISOString();
    const twelveMinAgo = new Date(Date.now() - 12 * 60 * 1000).toISOString();

    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue([
      JSON.stringify({ timestamp: twoMinAgo, agent_id: 'fast-agent', subagent_type: 'explorer' }),
      JSON.stringify({ timestamp: sevenMinAgo, agent_id: 'slow-agent', subagent_type: 'backend-system-architect' }),
      JSON.stringify({ timestamp: twelveMinAgo, agent_id: 'hung-agent', subagent_type: 'test-generator' }),
    ].join('\n'));

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.systemMessage).toContain('WARNING');
    expect(result.systemMessage).toContain('CRITICAL');
    expect(result.systemMessage).not.toContain('explorer');
  });

  it('handles empty spawn log gracefully', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue('');

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('handles corrupt spawn log entries gracefully', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue('not valid json\n{also broken');

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // ─── Zombie reaping (#1882) ───────────────────────────────────────
  // Spawns older than MAX_SPAWN_AGE_MS (24h) are treated as zombies
  // from prior sessions and silently dropped. Without this, watchdog
  // accumulates noise across sessions until the operator stops reading
  // it and misses a real hang.

  it('silently drops zombie spawn older than 24h cap', () => {
    const twoDaysAgo = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: twoDaysAgo, agent_id: 'zombie', subagent_type: 'workflow-architect' })
    );

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.systemMessage).toBeUndefined();
  });

  it('still warns for an agent JUST under the 24h cap', () => {
    // 23h59m old — still inside the cap, still critical
    const justUnder = new Date(Date.now() - (24 * 60 * 60 * 1000 - 60 * 1000)).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: justUnder, agent_id: 'aged', subagent_type: 'security-auditor' })
    );

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.systemMessage).toContain('CRITICAL');
    expect(result.systemMessage).toContain('security-auditor');
  });

  it('only legitimate recent spawn surfaces when mixed with zombies', () => {
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
    const elevenMinAgo = new Date(Date.now() - 11 * 60 * 1000).toISOString();

    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue([
      JSON.stringify({ timestamp: sevenDaysAgo, agent_id: 'zombie-1', subagent_type: 'agents-view-editor' }),
      JSON.stringify({ timestamp: sevenDaysAgo, agent_id: 'zombie-2', subagent_type: 'manifest-reconciler' }),
      JSON.stringify({ timestamp: sevenDaysAgo, agent_id: 'zombie-3', subagent_type: 'opus-sweeper' }),
      JSON.stringify({ timestamp: elevenMinAgo, agent_id: 'real-hung', subagent_type: 'backend-system-architect' }),
    ].join('\n'));

    const result = agentWatchdog(makeInput(), testCtx);

    expect(result.systemMessage).toContain('CRITICAL');
    expect(result.systemMessage).toContain('backend-system-architect');
    expect(result.systemMessage).not.toContain('agents-view-editor');
    expect(result.systemMessage).not.toContain('manifest-reconciler');
    expect(result.systemMessage).not.toContain('opus-sweeper');
  });
});
